sql:
SELECT food_id, COUNT(*) AS review_count
FROM reviews
GROUP BY food_id;

SELECT DISTINCT food_name, description
FROM foods
ORDER BY food_name;

SELECT 
    (SELECT COUNT(*) FROM reviews WHERE food_id = 1) AS num_reviews,
    (SELECT COUNT(*) FROM ratings WHERE food_id = 1) AS num_ratings;

SELECT c.population AS average_population
FROM countries c
WHERE c.country_name = 'Canada';
